mapper.select:
SELECT
COUNT(1) AS `totalOrderCount`,
COALESCE(SUM(CASE
	WHEN mall_order_info.`create_time`  >=  #{todayStart}
		AND mall_order_info.`create_time`  <  #{todayEnd}
	THEN 1 ELSE 0 END), 0) AS `todayOrderCount`,
COALESCE(SUM(CASE WHEN mall_order_info.`is_pay` = '1' THEN 1 ELSE 0 END), 0) AS `paidOrderCount`,
COALESCE(SUM(CASE
	WHEN mall_order_info.`is_pay` = '1'
		AND mall_order_info.`payment_time`  >=  #{todayStart}
		AND mall_order_info.`payment_time`  <  #{todayEnd}
	THEN 1 ELSE 0 END), 0) AS `todayPaidOrderCount`,
COALESCE(SUM(CASE WHEN mall_order_info.`is_pay` = '1' THEN mall_order_info.`payment_price` ELSE 0 END), 0) AS `totalPaidAmount`,
COALESCE(SUM(CASE
	WHEN mall_order_info.`is_pay` = '1'
		AND mall_order_info.`payment_time`  >=  #{todayStart}
		AND mall_order_info.`payment_time`  <  #{todayEnd}
	THEN mall_order_info.`payment_price` ELSE 0 END), 0) AS `todayPaidAmount`
FROM mall_order_info mall_order_info
WHERE mall_order_info.`del_flag` = '0'
